            op_type = type(node.op)
            if op_type in operators:
                left = eval_node(node.left)
                right = eval_node(node.right)
                # Prevent potential DoS via extremely large exponents
                if op_type == ast.Pow and (right > 1000 or right < -1000):
                    raise ValueError("Exponent too large")
                return operators[op_type](left, right)
            raise TypeError(f"Unsupported binary operator: {op_type}")

        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type in unary_operators:
                return unary_operators[op_type](eval_node(node.operand))
            raise TypeError(f"Unsupported unary operator: {op_type}")

        else:
            raise TypeError(f"Unsupported expression node: {type(node)}")

    try:
        # Parse the query into an AST. mode='eval' ensures only a single expression is allowed.
        tree = ast.parse(query, mode='eval')
        result = eval_node(tree.body)
        return str(result)
    except (SyntaxError, TypeError, ValueError, ZeroDivisionError) as e:
        return f"Error: {str(e)}"
    except Exception:
        return "Error: An unexpected error occurred during evaluation."
